const config = $input.first().json;
const keywords = config.keywords.split(',').map(k => k.trim()).filter(k => k.length > 0);

const staticData = $getWorkflowStaticData('global');
const history = staticData.contentHistory || [];

const industry = (config.industry || '').trim();
const audience = (config.targetAudience || '').trim();

// Build keyword pool — with 12 seeds we already have good variety
const pool = [];
keywords.forEach(k => pool.push(k));
if (industry) {
  pool.push(industry + ' trends');
  pool.push(industry + ' challenges');
  pool.push(industry + ' automation');
  pool.push(industry + ' cost reduction');
}
if (audience) {
  pool.push(audience + ' priorities');
  keywords.slice(0, 4).forEach(k => pool.push(audience + ' ' + k));
}
keywords.forEach(k => {
  pool.push(k + ' trends ' + new Date().getFullYear());
  pool.push(k + ' ROI');
});

const seen = new Set();
const uniquePool = pool.filter(k => {
  const lower = k.toLowerCase();
  if (seen.has(lower)) return false;
  seen.add(lower);
  return true;
});

// Rotate keyword — avoid last 8 runs
const recentPrimaries = history.slice(-8).flatMap(h => [
  (h.primaryKeyword || '').toLowerCase(),
  (h.queryKeyword || '').toLowerCase()
]).filter(Boolean);
let primary = uniquePool.find(k => !recentPrimaries.includes(k.toLowerCase()));
if (!primary) primary = uniquePool[history.length % uniquePool.length];

// Rotate question prefixes
const allPrefixes = ['what is', 'how to', 'why', 'best', 'top', 'latest', 'future of', 'how does', 'when should', 'cost of', 'risks of', 'alternatives to'];
const startIdx = history.length % allPrefixes.length;
const questionPrefixes = [];
for (let i = 0; i < 4; i++) {
  questionPrefixes.push(allPrefixes[(startIdx + i) % allPrefixes.length]);
}
const questionQueries = questionPrefixes.map(p => p + ' ' + primary);

// ARTICLE STRUCTURE ROTATION — 3 different formats so articles don't all look the same
const structures = [
  {
    name: 'deep-dive',
    description: 'Deep-dive analysis: Start with a bold claim backed by data. Use numbered sections with specific examples. End with a contrarian take.',
    format: 'numbered-analysis'
  },
  {
    name: 'problem-solution',
    description: 'Problem-Solution: Open with a real pain point (quote a CIO or cite a survey). Walk through the problem with specifics. Present 2-3 solutions with pros/cons. End with a decision framework.',
    format: 'problem-solution'
  },
  {
    name: 'case-study',
    description: 'Case Study / News Analysis: Lead with a specific company or event. Analyze what happened, why it matters, and what CIOs should do about it. Include a timeline or comparison table.',
    format: 'news-analysis'
  }
];
const structureIndex = history.length % structures.length;
const articleStructure = structures[structureIndex];

return [{
  json: {
    ...config,
    keywordList: keywords,
    primaryKeyword: primary,
    questionQueries: questionQueries,
    keywordPool: uniquePool,
    runNumber: history.length + 1,
    locationCode: 2840,
    languageCode: 'en',
    articleStructure: articleStructure
  }
}];

// Merge Google Autocomplete + Serper.dev results
let autocompleteSuggestions = [];
let questionSuggestions = [];
let serpData = {};
let peopleAlsoAsk = [];
let relatedSearches = [];
let featuredSnippet = null;

// Parse Autocomplete - Keywords
try {
  const auto = $('Autocomplete - Keywords').first().json;
  if (Array.isArray(auto) && auto[1]) {
    autocompleteSuggestions = auto[1].map(s => ({ keyword: s, source: 'autocomplete' }));
  } else if (auto.data || auto.suggestions) {
    autocompleteSuggestions = (auto.data || auto.suggestions || []).map(s => ({ keyword: typeof s === 'string' ? s : s.value || s.keyword || '', source: 'autocomplete' }));
  }
} catch(e) {}

// Parse Autocomplete - Questions
try {
  const quest = $('Autocomplete - Questions').first().json;
  if (Array.isArray(quest) && quest[1]) {
    questionSuggestions = quest[1].map(s => ({ question: s, source: 'autocomplete_questions' }));
  } else if (quest.data || quest.suggestions) {
    questionSuggestions = (quest.data || quest.suggestions || []).map(s => ({ question: typeof s === 'string' ? s : s.value || s.keyword || '', source: 'autocomplete_questions' }));
  }
} catch(e) {}

// Parse Serper.dev SERP results
try {
  const serp = $('Serper - SERP + PAA').first().json;

  // Organic results
  serpData = {
    totalResults: serp.organic ? serp.organic.length : 0,
    topResults: (serp.organic || []).slice(0, 10).map(r => ({
      title: r.title, url: r.link, description: r.snippet, position: r.position
    }))
  };

  // People Also Ask (GOLD for AEO)
  peopleAlsoAsk = (serp.peopleAlsoAsk || []).map(p => ({
    question: p.question,
    snippet: p.snippet || '',
    title: p.title || '',
    link: p.link || ''
  }));

  // Related Searches
  relatedSearches = (serp.relatedSearches || []).map(r => ({
    query: r.query
  }));

  // Featured Snippet
  if (serp.answerBox) {
    featuredSnippet = {
      type: serp.answerBox.type || 'unknown',
      title: serp.answerBox.title || '',
      answer: serp.answerBox.answer || serp.answerBox.snippet || '',
      source: serp.answerBox.link || ''
    };
  }

  // Knowledge Graph
  if (serp.knowledgeGraph) {
    serpData.knowledgeGraph = {
      title: serp.knowledgeGraph.title || '',
      type: serp.knowledgeGraph.type || '',
      description: serp.knowledgeGraph.description || ''
    };
  }
} catch(e) {}

const config = $('Client Configuration').first().json;

// Load content history for deduplication across runs
const staticData = $getWorkflowStaticData('global');
const contentHistory = staticData.contentHistory || [];

return [{ json: {
  clientConfig: config,
  keywordData: {
    autocompleteSuggestions,
    questionSuggestions,
    relatedSearches,
    serpData,
    peopleAlsoAsk,
    featuredSnippet,
    totalDataPoints: autocompleteSuggestions.length + questionSuggestions.length + peopleAlsoAsk.length + relatedSearches.length
  },
  contentHistory: {
    usedKeywords: contentHistory.map(h => h.primaryKeyword).filter(Boolean),
    usedAngles: contentHistory.map(h => h.articleAngle).filter(Boolean),
    usedTitles: contentHistory.map(h => h.articleTitle).filter(Boolean),
    usedTopStories: contentHistory.map(h => h.topStoryTitle).filter(Boolean),
    totalPreviousRuns: contentHistory.length
  }
}}];

