const response = $input.first().json;

// Robust text extraction — handles Gemini, OpenAI, and raw formats
function extractText(r) {
  if (typeof r.text === 'string' && r.text.length > 0) return r.text;
  if (typeof r.message === 'string' && r.message.length > 0) return r.message;
  if (r.output && Array.isArray(r.output)) {
    return r.output.map(o => {
      if (typeof o.content === 'string') return o.content;
      if (Array.isArray(o.content)) return o.content.map(c => c.text || '').join('');
      return o.text || '';
    }).join('');
  }
  if (r.content && r.content.parts) return r.content.parts.map(p => p.text || '').join('');
  if (r.content && Array.isArray(r.content)) return r.content.map(c => c.text || '').join('');
  if (r.candidates && Array.isArray(r.candidates)) return r.candidates.map(c => c.content && c.content.parts ? c.content.parts.map(p => p.text || '').join('') : '').join('');
  if (typeof r.output === 'string') return r.output;
  return JSON.stringify(r);
}

let text = extractText(response);
text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

try {
  const parsed = JSON.parse(text);

  // === DEDUPLICATION: Filter recently used stories (last 4 weeks) ===
  const staticData = $getWorkflowStaticData('global');
  const histEntries = staticData.contentHistory || [];
  // Only filter against last 4 runs — older stories can be reused with fresh angles
  const recentEntries = histEntries.slice(-4);
  const usedUrls = new Set(recentEntries.flatMap(h => h.storyUrls || []));
  const usedTitlesLow = new Set(recentEntries.map(h => (h.topStoryTitle || '').toLowerCase()).filter(Boolean));

  // Save originals for fallback
  const origRanked = parsed.rankedStories ? parsed.rankedStories.slice() : [];
  const origNewsletter = parsed.newsletterStories ? parsed.newsletterStories.slice() : [];

  // Filter ranked stories — remove recently featured
  if (parsed.rankedStories && parsed.rankedStories.length > 0) {
    const filtered = parsed.rankedStories.filter(s =>
      !usedUrls.has(s.url) && !usedTitlesLow.has((s.title || '').toLowerCase())
    );
    // Fallback: if too few stories remain, restore originals
    parsed.rankedStories = filtered.length >= 3 ? filtered : origRanked;
  }

  // Filter newsletter stories — remove recent duplicates
  if (parsed.newsletterStories && parsed.newsletterStories.length > 0) {
    const filtered = parsed.newsletterStories.filter(s => !usedUrls.has(s.url));
    parsed.newsletterStories = filtered.length >= 3 ? filtered : origNewsletter;
  }

  // If top story was recently used, swap to next fresh one
  if (parsed.topStory) {
    const topUsed = usedUrls.has(parsed.topStory.url) || usedTitlesLow.has((parsed.topStory.title || '').toLowerCase());
    if (topUsed && parsed.rankedStories && parsed.rankedStories.length > 0) {
      // Find first story that differs from current top
      const alt = parsed.rankedStories.find(s => s.url !== parsed.topStory.url);
      if (alt) {
        parsed.topStory = {
          title: alt.title || '',
          url: alt.url || '',
          source: alt.source || '',
          fullSummary: alt.summary || alt.fullSummary || '',
          suggestedAngle: alt.aeoAngle || alt.suggestedAngle || '',
          supportingData: alt.keyDataPoints || alt.supportingData || []
        };
      }
    }
  }

  parsed._dedup = { storiesFiltered: usedUrls.size, historyEntries: histEntries.length, recentWindow: recentEntries.length };
  return [{ json: parsed }];
} catch(e) {
  return [{ json: { trendAnalysis: { topTrends: [], industryMomentum: '' }, rankedStories: [], topStory: { title: 'Research unavailable', url: '', source: '', fullSummary: text.substring(0, 500), suggestedAngle: '', supportingData: [] }, newsletterStories: [] } }];
}

